args.sparql:
SELECT ?musician ?musicianLabel
WHERE {
  ?musician wdt:P106 wd:Q639669.
  ?musician wdt:P19 ?birthPlace.
  {
    ?birthPlace wdt:P131* wd:Q99.
  } UNION {
    ?birthPlace wdt:P131* wd:Q1147.
  } UNION {
    ?birthPlace wdt:P131* wd:Q1317.
  }

  ?musician p:P166 ?awardStatement.
  ?awardStatement ps:P166 ?award.
  ?award wdt:P31 wd:Q41254.
  ?awardStatement pq:P585 ?time.
  FILTER(STRSTARTS(STR(?time), "2022")).

  OPTIONAL { ?musician rdfs:label ?musicianLabel. FILTER(LANG(?musicianLabel) = "en"). }
}

SELECT DISTINCT ?musician ?musicianLabel
WHERE {
  VALUES ?state { wd:Q99 wd:Q1147 wd:Q1317 }

  # Grammy winners in 2022 (ceremony year)
  {
    SELECT ?musician WHERE {
      ?musician p:P166 ?awardStatement.
      ?awardStatement ps:P166 ?award;
                      pq:P585 ?time.
      ?award wdt:P361 wd:Q41254.
      FILTER(STRSTARTS(STR(?time), "2022"))
    }
  }

  # Verify musician is from West Coast (CA/OR/WA birthplace)
  ?musician wdt:P106 wd:Q639669.  # occupation: musician
  ?musician wdt:P19 ?birthPlace.
  ?birthPlace wdt:P131+ ?state.

  OPTIONAL { ?musician rdfs:label ?musicianLabel FILTER(LANG(?musicianLabel) = "en"). }
}
LIMIT 50

SELECT DISTINCT ?musician ?name
WHERE {
  VALUES ?state { wd:Q99 wd:Q1147 wd:Q1317 }

  # West Coast US musicians
  ?musician wdt:P106 wd:Q639669;
            wdt:P19 ?birthPlace.
  ?birthPlace wdt:P131 ?state.

  # Grammy Award winners in 2022
  ?musician p:P166 ?awardStatement.
  ?awardStatement ps:P166 ?awardItem;
                  pq:P585 ?date.
  ?awardItem wdt:P361 wd:Q41254.
  FILTER(STRSTARTS(STR(?date), "2022"))

  OPTIONAL { ?musician rdfs:label ?name FILTER(LANG(?name) = "en"). }
}
LIMIT 50

SELECT DISTINCT ?musician ?name
WHERE {
  VALUES ?westCoastState { wd:Q99 wd:Q1147 wd:Q1317 }

  # West Coast musicians (born in CA, OR, WA)
  ?musician wdt:P106 wd:Q639669;
            wdt:P19 ?birthPlace.
  ?birthPlace wdt:P131 ?westCoastState.

  # Grammy Award winners in 2022
  ?musician p:P166 ?awardStatement.
  ?awardStatement ps:P166 ?awardCategory.
  ?awardCategory wdt:P179 wd:Q41254.
  ?awardStatement pq:P585 ?date.
  FILTER(STRSTARTS(STR(?date), "2022"))

  OPTIONAL { ?musician rdfs:label ?name FILTER(LANG(?name) = "en"). }
}
LIMIT 50

SELECT DISTINCT ?musician ?name
WHERE {
  VALUES ?state { wd:Q99 wd:Q1147 wd:Q1317 }

  # West Coast US musicians (born in CA, OR, WA)
  ?musician wdt:P106 wd:Q639669;
            wdt:P19 ?birthPlace.
  ?birthPlace wdt:P131 ?state.

  # Grammy Award winners in 2022
  ?musician p:P166 ?awardStatement.
  ?awardStatement ps:P166 ?award;
                  pq:P585 ?date.
  ?award wdt:P31 wd:Q41254.

  FILTER(STRSTARTS(STR(?date), "2022"))

